from flask import Blueprint, request, jsonify
from models import Appointment, db

appointment_routes = Blueprint('appointments', __name__)

@appointment_routes.route('/appointments', methods=['POST'])
def request_appointment():
    # FR-01: Patients can request appointments
    data = request.get_json()
    # TODO: Validate input fields and NHS number # FR-07
    new_appointment = Appointment(
        patient_name=data['name'],
        nhs_number=data['nhs_number'],
        date_of_birth=data['date_of_birth'],
        preferred_datetime=data['preferred_datetime'],
        reason_for_visit=data['reason_for_visit']
    )
    db.session.add(new_appointment)
    db.session.commit()
    return jsonify({'message': 'Appointment requested successfully'}), 201

